What does the following program print to **stdout**?

```cpp
#include <iostream>

int halve(int x)
{
    std::cerr << "halving " << x << '\n';
    return x / 2;
}

int main()
{
    std::cout << halve(9) << '\n';
    return 0;
}
```

What does the following program print?

```cpp
#include <iostream>

void report(int a, int b)
{
    std::cout << a + b << '\n';
}

int main()
{
    int x = 3;
    int y = 4;
    report(x, y);
    report(y, x);
    return 0;
}
```
